```typescript
class GestionnaireTaches implements ServiceTaches {
  private taches: Tache[] = [];
  private prochainId: number = 1;

  ajouter(titre: string, description?: string): Tache {
    const nouvelleTache: Tache = {
      id: this.prochainId++,
      titre,
      description,
      terminee: false,
      creeeLe: new Date()
    };
    this.taches.push(nouvelleTache);
    return nouvelleTache;
  }

  lister(): Tache[] {
    return [...this.taches]; // Retourne une copie pour éviter la mutation externe
  }

  marquerTerminee(id: number): boolean {
    const tache = this.taches.find(t => t.id === id);
    if (tache) {
      tache.terminee = true;
      return true;
    }
    return false;
  }

  supprimer(id: number): boolean {
    const index = this.taches.findIndex(t => t.id === id);
    if (index !== -1) {
      this.taches.splice(index, 1);
      return true;
    }
    return false;
  }
}
```

```typescript
